Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
     <PLACEHOLDER>
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              if(done) done(end === true ? null : end)
              else if(end && end !== true) {
                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-     if (!done) {
-       doneLackingErr = new Error('no done callback supplied')
-     }
In the mutated code, <PLACEHOLDER> has the value:

+     if (!done) {}


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-490cb10/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the original code creates a `doneLackingErr = new Error('no done callback supplied')` when no `done` callback is provided. The mutated code has an empty block `if (!done) {}`, so `doneLackingErr` remains `undefined`.

The observable behavior difference: when a stream ends with an error and no `done` callback is provided, the original code logs `doneLackingErr` (the Error object) to `console.warn` before throwing. With the mutation, `doneLackingErr` is `undefined`, so `console.warn(undefined)` is called instead.

I can detect this by spying on `console.warn` and checking what value was passed to it.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain without done callback - error handling", () => {
  it("should console.warn an Error object (not undefined) when stream ends with error and no done callback", (done) => {
    const warnSpy = jest.spyOn(console, "warn").mockImplementation(() => {});

    // Create a source that emits one item then ends with an error
    const error = new Error("stream error");
    let callCount = 0;
    const source = (_abort: any, cb: (end: any, data?: any) => void) => {
      callCount++;
      if (callCount === 1) {
        cb(null, "data");
      } else {
        cb(error);
      }
    };

    // No done callback provided
    const sink = drain(null, null);
    sink(source);

    // Use setImmediate to allow the async operations to complete
    setImmediate(() => {
      try {
        // The console.warn should have been called with an Error instance (not undefined)
        expect(warnSpy).toHaveBeenCalled();
        const warnArg = warnSpy.mock.calls[0][0];
        expect(warnArg).toBeInstanceOf(Error);
        expect((warnArg as Error).message).toBe("no done callback supplied");
        warnSpy.mockRestore();
        done();
      } catch (e) {
        warnSpy.mockRestore();
        done(e);
      }
    });
  });
});
```
